// src/components/Footer.jsx

import { useEffect, useRef } from 'react';

// ─── Datos ────────────────────────────────────────────────────────────────────
const GITHUB   = 'https://github.com/ruben14marco';
const LINKEDIN = 'https://www.linkedin.com/in/rubén-marco-aa992b234';
const GMAIL    = 'https://mail.google.com/mail/?view=cm&to=ruben14marco@gmail.com';
const YEAR     = new Date().getFullYear();

const NAV_LINKS = [
  { label: 'Sobre mí',    href: '#about'      },
  { label: 'Experiencia', href: '#experience'  },
  { label: 'Proyectos',   href: '#projects'    },
  { label: 'Contacto',    href: '#contact'     },
];


// ─── Componente principal ─────────────────────────────────────────────────────
export default function Footer() {
  const canvasRef = useRef(null);

  // Animación de partículas — más lentas y escasas que el resto del portfolio
  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx    = canvas.getContext('2d');
    const footer = canvas.parentElement;
    let animId;
    let mouse = { x: -9999, y: -9999 };

    const N    = 28;   // pocas partículas, el footer debe respirar
    const CONN = 160;  // distancia máxima para conectar puntos
    const MD   = 150;  // distancia máxima al ratón

    let W, H, pts;

    const resize = () => {
      W = canvas.width  = footer.offsetWidth;
      H = canvas.height = footer.offsetHeight;
    };

    const init = () => {
      pts = Array.from({ length: N }, () => ({
        x:  Math.random() * W,
        y:  Math.random() * H,
        vx: (Math.random() - 0.5) * 0.18,  // velocidad baja a propósito
        vy: (Math.random() - 0.5) * 0.18,
        r:  Math.random() * 2.5 + 1,
        a:  Math.random() * 0.3 + 0.15,    // alpha individual por partícula
      }));
    };

    const tick = () => {
      ctx.clearRect(0, 0, W, H);

      for (let i = 0; i < N; i++) {
        const p = pts[i];
        p.x += p.vx; p.y += p.vy;
        if (p.x < 0 || p.x > W) p.vx *= -1;
        if (p.y < 0 || p.y > H) p.vy *= -1;

        // punto
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(232,58,58,${p.a})`;
        ctx.fill();

        // líneas entre partículas cercanas
        for (let j = i + 1; j < N; j++) {
          const q = pts[j];
          const d = Math.hypot(p.x - q.x, p.y - q.y);
          if (d < CONN) {
            ctx.beginPath();
            ctx.moveTo(p.x, p.y);
            ctx.lineTo(q.x, q.y);
            ctx.strokeStyle = `rgba(232,58,58,${(1 - d / CONN) * 0.12})`;
            ctx.lineWidth = 0.5;
            ctx.stroke();
          }
        }

        // línea al ratón cuando está cerca
        const dm = Math.hypot(p.x - mouse.x, p.y - mouse.y);
        if (dm < MD) {
          ctx.beginPath();
          ctx.moveTo(p.x, p.y);
          ctx.lineTo(mouse.x, mouse.y);
          ctx.strokeStyle = `rgba(232,58,58,${(1 - dm / MD) * 0.3})`;
          ctx.lineWidth = 0.7;
          ctx.stroke();
        }
      }

      animId = requestAnimationFrame(tick);
    };

    const onMove  = (e) => { const r = canvas.getBoundingClientRect(); mouse.x = e.clientX - r.left; mouse.y = e.clientY - r.top; };
    const onLeave = ()  => { mouse.x = -9999; mouse.y = -9999; };

    footer.addEventListener('mousemove',  onMove);
    footer.addEventListener('mouseleave', onLeave);
    window.addEventListener('resize', () => { resize(); init(); });

    resize(); init(); tick();

    return () => {
      cancelAnimationFrame(animId);
      footer.removeEventListener('mousemove',  onMove);
      footer.removeEventListener('mouseleave', onLeave);
    };
  }, []);


  // ─── Render ──────────────────────────────────────────────────────────────────
  return (
    <footer style={s.footer}>

      {/* Línea roja degradada en el borde superior */}
      <div style={s.topLine} />

      {/* Canvas de partículas */}
      <canvas ref={canvasRef} style={s.canvas} />

      {/* Texto fantasma decorativo en el fondo */}
      <div style={s.bgText} aria-hidden="true">RUBÉN MARCO</div>

      <div style={s.inner}>

        {/* ── Fila superior: logo + badge + nav ── */}
        <div style={s.top}>
          <div>
            <div style={s.logo}>RM<span style={s.logoDot}>.</span></div>
            <p style={s.tagline}>
              Desarrollador Full Stack con base en Madrid.<br />
              Buscando el primer equipo donde crecer de verdad.
            </p>
          </div>

          <div style={s.right}>
            <span style={s.badge}>
              <span style={s.badgeDot} />
              Open to work
            </span>
            <nav style={s.nav}>
              {NAV_LINKS.map(({ label, href }) => (
                <a key={href} href={href} style={s.navLink}
                  onMouseEnter={e => e.currentTarget.style.color = '#e83a3a'}
                  onMouseLeave={e => e.currentTarget.style.color = 'rgba(255,255,255,0.28)'}
                >
                  {label}
                </a>
              ))}
            </nav>
          </div>
        </div>

        {/* ── Fila inferior: copyright + iconos sociales ── */}
        <div style={s.bottom}>
          <p style={s.copy}>
            © {YEAR} <strong style={s.copyStrong}>Rubén Marco</strong> — Hecho con React
          </p>

          <div style={s.social}>
            <SocialIcon href={GITHUB} title="GitHub">
              <GithubIcon />
            </SocialIcon>
            <SocialIcon href={LINKEDIN} title="LinkedIn">
              <LinkedInIcon />
            </SocialIcon>
            <SocialIcon href={GMAIL} title="Email">
              <MailIcon />
            </SocialIcon>
          </div>
        </div>

      </div>
    </footer>
  );
}


// ─── Botón de red social con hover ───────────────────────────────────────────
function SocialIcon({ href, title, children }) {
  return (
    <a
      href={href}
      target="_blank"
      rel="noreferrer"
      title={title}
      style={s.icon}
      onMouseEnter={e => {
        e.currentTarget.style.borderColor = 'rgba(232,58,58,0.45)';
        e.currentTarget.style.color       = '#e83a3a';
        e.currentTarget.style.background  = 'rgba(232,58,58,0.07)';
      }}
      onMouseLeave={e => {
        e.currentTarget.style.borderColor = 'rgba(255,255,255,0.07)';
        e.currentTarget.style.color       = 'rgba(255,255,255,0.28)';
        e.currentTarget.style.background  = 'rgba(255,255,255,0.02)';
      }}
    >
      {children}
    </a>
  );
}


